#include <iostream>
#include <string>
#include <sstream>

int main() {
    int number;
    std::cin >> number;

    int sum = 0;
    int tempNumber = number;

    if (tempNumber < 0) {
        tempNumber = -tempNumber;
    }

    while (tempNumber > 0) {
        int digit = tempNumber % 10;
        sum += digit;
        tempNumber /= 10;
    }

    std::cout << sum << std::endl;
    return 0;
}
